SELECT district_name, contact_person, contact_phone
FROM districts
WHERE priority_score = (
  SELECT MAX(priority_score)
  FROM districts
);

SELECT SUM(deceased) AS total_deceased
FROM health_statistics
WHERE disease_id = (SELECT disease_id FROM disease_types WHERE disease_name = 'Influenza');

SELECT T1.district_name, T1.population
FROM districts AS T1
WHERE T1.priority_score = (SELECT MAX(priority_score) FROM districts);

SELECT district_id, population, priority_score
FROM districts
WHERE population > 1000000;

SELECT district_name, contact_person, contact_phone
FROM districts
WHERE population = (SELECT MAX(population) FROM districts);

SELECT district_name, population 
FROM districts 
WHERE population = (SELECT MAX(population) FROM districts);

SELECT SUM(d.population) AS total_population
FROM districts d
WHERE d.priority_score > (SELECT AVG(priority_score) FROM districts);
